/**
 * Card Graph — AI Parse Configuration
 *
 * Sub-tab for configuring and managing the AI-powered card extraction pipeline.
 * Displays model settings, prompt templates, context toggles, and usage stats.
 */
var AiParseAdmin = {
    initialized: false,
    config: null,
    dirty: false,

    DEFAULT_SYSTEM_PROMPT: 'You are a baseball card auction transcript analyst. You extract individual card items being auctioned from transcription text generated by Whisper from live auction audio.\n\nRULES:\n- Each auction item is a distinct card or lot being sold\n- Extract ONLY actual items being auctioned, not casual conversation about cards\n- The auctioneer typically announces each card with player name, card details (maker, style, parallel, serial number), and bidding\n- Whisper may misspell player names or card terms - use your knowledge to correct them\n- Multi-player lots (e.g. "Ohtani, Sasaki, and Yamamoto bundle") count as ONE item\n- Graded cards may mention PSA, BGS, SGC with a grade number\n- Common card terms: rookie, auto/autograph, refractor, parallel, /25 (serial numbered), game-used, relic, insert, sapphire, chrome, mosaic, bowman, topps, panini\n- Cards that span segment boundaries (auctioneer starts describing at end of segment) should still be captured with what info is available',

    DEFAULT_SEGMENT_PROMPT: 'Analyze this auction transcript segment and extract each card being auctioned.\n\nSEGMENT INFO:\n- Segment number: {{segment_number}}\n- Time window: {{start_time}} to {{end_time}}\n- Expected items in this window: approximately {{expected_count}} cards\n\n{{#if auction_items}}\nAUCTION ITEMS SOLD IN THIS TIME WINDOW (for cross-reference):\n{{auction_items}}\n{{/if}}\n\n{{#if player_list}}\nKNOWN PLAYERS (correct Whisper misspellings to these):\n{{player_list}}\n{{/if}}\n\n{{#if prev_segment_last_card}}\nPREVIOUS SEGMENT ENDED WITH: {{prev_segment_last_card}}\n(If this segment starts mid-description of that card, skip it unless new info is added)\n{{/if}}\n\nTRANSCRIPT TEXT:\n"""\n{{transcript_text}}\n"""\n\nIMPORTANT RULES FOR FIELD EXTRACTION:\n- "team": ALWAYS fill using your baseball knowledge. Every MLB player has a current/most recent team. Never return null.\n- "maker": ALWAYS infer from the product/set name. Mappings:\n  Topps = Chrome, Cosmic Chrome, Archives, Heritage, Allen & Ginter, Stadium Club, Tier One, Gallery, Inception, Luminaries, Fire, Big League, Sterling, Tribute, Update, Series 1/2, Opening Day, Holiday, Finest, Gold Label\n  Panini = Mosaic, Prizm, Select, Donruss, Optic, Spectra, Flawless, National Treasures, Illusions, Chronicles, Absolute, Immaculate, Obsidian\n  Bowman = 1st Bowman, Bowman Chrome, Bowman Sterling, Bowman Draft, Bowman Best\n  If truly unknown, return null.\n- "style": The PRODUCT or SET name only (e.g. "Chrome", "Mosaic", "Tier One", "Prizm", "Select"). This is the main product line, NOT an insert set or parallel.\n- "parallel": The specific PARALLEL or VARIATION (e.g. "Refractor", "Green Wave", "Sapphire", "Black Gold", "Silver Pack Mojo", "Purple Auto"). NOT the insert set name.\n- Insert sets go in card_description, not style. Examples of insert sets: "All Aces", "Greatest Loading", "Cosmic Light Speed", "35th Anniversary Rookie Cup". These describe a sub-set within a product.\n- "price": Extract the final sale price if announced (e.g. "sold for $4.50", "going at $2", "$3.50"). Number without $. If not mentioned, null.\n- "card_description": A COMPLETE readable summary. Include: [Maker] [Year if known] [Product] [Insert set if any] [Parallel if any] [Serial if any] [Rookie/Auto/Relic]. Example: "2024 Topps Chrome Cosmic Light Speed Refractor RC /199" or "2024 Panini Mosaic All Aces Insert". Never just "Rookie" — always include the full context.\n\nReturn a JSON array. Each item:\n{\n  "player_name": "Full corrected name",\n  "team": "Team name (ALWAYS fill)",\n  "maker": "Topps/Panini/Bowman/etc (ALWAYS infer from set)",\n  "style": "Product/set name only (Chrome, Mosaic, Tier One) or null",\n  "parallel": "Parallel/variation name (Refractor, Sapphire, Black Gold) or null",\n  "card_number": "Card number if mentioned or null",\n  "serial_number": "/25 format or null",\n  "card_description": "COMPLETE description — never just one word",\n  "price": null or number,\n  "is_rookie": true/false,\n  "is_autograph": true/false,\n  "is_relic": true/false,\n  "is_graded": true/false,\n  "grade_info": "PSA 10 or null",\n  "confidence": 0.0-1.0,\n  "confidence_reason": "Brief explanation",\n  "approximate_position": "early/middle/late in segment",\n  "raw_text_excerpt": "Exact words from transcript for this card"\n}\n\nReturn ONLY the JSON array, no other text.',

    init: function() {
        var panel = document.getElementById('tx-panel-aiparse');
        if (!panel) return;

        if (!this.initialized) {
            this.renderSkeleton(panel);
            this.initialized = true;
        }

        this.loadConfig();
    },

    renderSkeleton: function(panel) {
        var h = [];
        h.push('<div class="aip-container">');

        // Header
        h.push('<div class="aip-header">');
        h.push('<h3 style="font-size:16px;font-weight:700;color:#1a1a2e;margin:0;">AI Parse Configuration</h3>');
        h.push('<div class="aip-header-actions">');
        h.push('<button class="btn btn-secondary btn-sm" id="aip-test-btn" disabled>Test Connection</button>');
        h.push('<button class="btn btn-success btn-sm" id="aip-save-btn" disabled>Save Config</button>');
        h.push('</div>');
        h.push('</div>');

        // Status bar
        h.push('<div id="aip-status" class="aip-status"></div>');

        // Main content grid
        h.push('<div class="aip-grid">');

        // ---- Left column: Model & Parameters ----
        h.push('<div class="aip-col-left">');

        // Model card
        h.push('<div class="aip-card">');
        h.push('<h4 class="aip-card-title">Model</h4>');
        h.push('<div class="aip-field">');
        h.push('<label>Provider</label>');
        h.push('<select id="aip-provider" class="aip-input">');
        h.push('<option value="openai">OpenAI</option>');
        h.push('<option value="gemini">Google Gemini</option>');
        h.push('<option value="groq">Groq</option>');
        h.push('</select>');
        h.push('</div>');
        h.push('<div class="aip-field">');
        h.push('<label>Model</label>');
        h.push('<select id="aip-model" class="aip-input"></select>');
        h.push('</div>');
        h.push('<div class="aip-field">');
        h.push('<label>API Key</label>');
        h.push('<div style="display:flex;gap:6px;">');
        h.push('<input type="password" id="aip-apikey" class="aip-input" placeholder="Paste your API key" style="flex:1;">');
        h.push('<button class="btn btn-secondary btn-sm" id="aip-toggle-key" title="Show/hide key">Show</button>');
        h.push('</div>');
        h.push('<div id="aip-key-status" class="aip-field-hint" style="margin-top:4px;font-weight:600;"></div>');
        h.push('<div id="aip-key-hint" class="aip-field-hint"></div>');
        h.push('</div>');
        h.push('</div>');

        // Parameters card
        h.push('<div class="aip-card">');
        h.push('<h4 class="aip-card-title">Parameters</h4>');
        h.push('<div class="aip-field">');
        h.push('<label>Temperature <span id="aip-temp-val" class="aip-badge">0.10</span></label>');
        h.push('<input type="range" id="aip-temperature" min="0" max="1" step="0.05" value="0.10" class="aip-range">');
        h.push('<div class="aip-field-hint">Lower = more deterministic. 0.05-0.15 recommended for extraction.</div>');
        h.push('</div>');
        h.push('<div class="aip-field">');
        h.push('<label>Max Output Tokens</label>');
        h.push('<input type="number" id="aip-max-tokens" class="aip-input" value="4096" min="256" max="8192" step="256">');
        h.push('</div>');
        h.push('</div>');

        // Context Signals card
        h.push('<div class="aip-card">');
        h.push('<h4 class="aip-card-title">Context Signals per Segment</h4>');
        h.push('<div class="aip-field-hint" style="margin-bottom:8px;">Data included in each segment request to help the AI make better decisions.</div>');
        h.push('<div class="aip-toggle-row">');
        h.push('<label class="aip-toggle"><input type="checkbox" id="aip-inc-auction" checked><span class="aip-toggle-label">Auction Items (sold in time window)</span></label>');
        h.push('<div class="aip-toggle-desc">Cross-reference: player names, titles, prices, timestamps of items sold during this segment</div>');
        h.push('</div>');
        h.push('<div class="aip-toggle-row">');
        h.push('<label class="aip-toggle"><input type="checkbox" id="aip-inc-players" checked><span class="aip-toggle-label">Known Player List</span></label>');
        h.push('<div class="aip-toggle-desc">Full names of players in the database — helps AI correct Whisper misspellings</div>');
        h.push('</div>');
        h.push('<div class="aip-toggle-row">');
        h.push('<label class="aip-toggle"><input type="checkbox" id="aip-inc-vocab" checked><span class="aip-toggle-label">Card Vocabulary</span></label>');
        h.push('<div class="aip-toggle-desc">Maker names (Topps, Panini), styles (Chrome, Mosaic), and specialty terms</div>');
        h.push('</div>');
        h.push('<div class="aip-toggle-row">');
        h.push('<label class="aip-toggle"><input type="checkbox" id="aip-inc-prev" checked><span class="aip-toggle-label">Previous Segment Context</span></label>');
        h.push('<div class="aip-toggle-desc">Last card from previous segment — handles boundary cards that span segments</div>');
        h.push('</div>');
        h.push('</div>');

        // Usage card
        h.push('<div class="aip-card">');
        h.push('<h4 class="aip-card-title">Usage Statistics</h4>');
        h.push('<div id="aip-usage">Loading...</div>');
        h.push('</div>');

        h.push('</div>'); // end left col

        // ---- Right column: Prompts ----
        h.push('<div class="aip-col-right">');

        // System prompt
        h.push('<div class="aip-card aip-card-prompt">');
        h.push('<div class="aip-prompt-header">');
        h.push('<h4 class="aip-card-title">System Prompt</h4>');
        h.push('<button class="btn btn-secondary btn-sm" id="aip-reset-system">Reset to Default</button>');
        h.push('</div>');
        h.push('<div class="aip-field-hint">Sets the AI\'s role and global rules. Sent once per request.</div>');
        h.push('<textarea id="aip-system-prompt" class="aip-textarea" rows="14"></textarea>');
        h.push('</div>');

        // Segment prompt
        h.push('<div class="aip-card aip-card-prompt">');
        h.push('<div class="aip-prompt-header">');
        h.push('<h4 class="aip-card-title">Segment Prompt Template</h4>');
        h.push('<button class="btn btn-secondary btn-sm" id="aip-reset-segment">Reset to Default</button>');
        h.push('</div>');
        h.push('<div class="aip-field-hint">Template for each segment. Variables: <code>{{segment_number}}</code>, <code>{{start_time}}</code>, <code>{{end_time}}</code>, <code>{{expected_count}}</code>, <code>{{auction_items}}</code>, <code>{{player_list}}</code>, <code>{{prev_segment_last_card}}</code>, <code>{{transcript_text}}</code></div>');
        h.push('<textarea id="aip-segment-prompt" class="aip-textarea" rows="26"></textarea>');
        h.push('</div>');

        h.push('</div>'); // end right col
        h.push('</div>'); // end grid
        h.push('</div>'); // end container

        panel.innerHTML = h.join('\n');

        // Bind events
        var self = this;
        document.getElementById('aip-save-btn').addEventListener('click', function() { self.saveConfig(); });
        document.getElementById('aip-test-btn').addEventListener('click', function() { self.testConnection(); });
        document.getElementById('aip-reset-system').addEventListener('click', function() {
            document.getElementById('aip-system-prompt').value = self.DEFAULT_SYSTEM_PROMPT;
            self.markDirty();
        });
        document.getElementById('aip-reset-segment').addEventListener('click', function() {
            document.getElementById('aip-segment-prompt').value = self.DEFAULT_SEGMENT_PROMPT;
            self.markDirty();
        });
        document.getElementById('aip-toggle-key').addEventListener('click', function() {
            var inp = document.getElementById('aip-apikey');
            if (inp.type === 'password') { inp.type = 'text'; this.textContent = 'Hide'; }
            else { inp.type = 'password'; this.textContent = 'Show'; }
        });
        document.getElementById('aip-temperature').addEventListener('input', function() {
            document.getElementById('aip-temp-val').textContent = parseFloat(this.value).toFixed(2);
            self.markDirty();
        });
        document.getElementById('aip-provider').addEventListener('change', function() {
            self.updateModelsForProvider(this.value);
            self.markDirty();
        });

        // Initialize model list
        self.updateModelsForProvider('openai');

        // Mark dirty on any input change
        ['aip-provider', 'aip-model', 'aip-apikey', 'aip-max-tokens',
         'aip-inc-auction', 'aip-inc-players', 'aip-inc-vocab', 'aip-inc-prev',
         'aip-system-prompt', 'aip-segment-prompt'].forEach(function(id) {
            var el = document.getElementById(id);
            if (el) el.addEventListener('input', function() { self.markDirty(); });
            if (el) el.addEventListener('change', function() { self.markDirty(); });
        });
    },

    PROVIDER_MODELS: {
        openai: [
            { value: 'gpt-4.1-mini', label: 'GPT-4.1 Mini (cheap, recommended)' },
            { value: 'gpt-4.1-nano', label: 'GPT-4.1 Nano (cheapest)' },
            { value: 'gpt-4o-mini', label: 'GPT-4o Mini' },
            { value: 'gpt-4.1', label: 'GPT-4.1 (powerful, costs more)' },
        ],
        gemini: [
            { value: 'gemini-2.5-flash', label: 'Gemini 2.5 Flash' },
            { value: 'gemini-2.0-flash', label: 'Gemini 2.0 Flash' },
            { value: 'gemini-2.0-flash-lite', label: 'Gemini 2.0 Flash Lite' },
        ],
        groq: [
            { value: 'llama-3.3-70b-versatile', label: 'Llama 3.3 70B' },
            { value: 'llama-3.1-8b-instant', label: 'Llama 3.1 8B Instant (fast)' },
            { value: 'mixtral-8x7b-32768', label: 'Mixtral 8x7B' },
            { value: 'gemma2-9b-it', label: 'Gemma 2 9B' },
        ],
    },

    PROVIDER_HINTS: {
        openai: 'API key from <a href="https://platform.openai.com/api-keys" target="_blank" rel="noopener">platform.openai.com</a>',
        gemini: 'Free key at <a href="https://aistudio.google.com/apikey" target="_blank" rel="noopener">Google AI Studio</a>',
        groq: 'Free key at <a href="https://console.groq.com/keys" target="_blank" rel="noopener">console.groq.com</a>',
    },

    markDirty: function() {
        this.dirty = true;
        var saveBtn = document.getElementById('aip-save-btn');
        if (saveBtn) { saveBtn.disabled = false; saveBtn.classList.add('btn-pulse'); }
    },

    updateModelsForProvider: function(provider) {
        var select = document.getElementById('aip-model');
        var models = this.PROVIDER_MODELS[provider] || [];
        select.innerHTML = '';
        models.forEach(function(m) {
            var opt = document.createElement('option');
            opt.value = m.value;
            opt.textContent = m.label;
            select.appendChild(opt);
        });
        var hint = document.getElementById('aip-key-hint');
        if (hint) hint.innerHTML = this.PROVIDER_HINTS[provider] || '';

        // Update key status — show per-provider saved key info
        var keyStatus = document.getElementById('aip-key-status');
        if (keyStatus && this.config) {
            var hasKey = this.config[provider + '_key_set'] || false;
            var keyHint = this.config[provider + '_key_hint'] || null;
            if (hasKey) {
                keyStatus.textContent = '\u2705 ' + provider.toUpperCase() + ' key saved (' + keyHint + ')';
                keyStatus.style.color = '#2e7d32';
            } else {
                keyStatus.textContent = '\u274c No ' + provider.toUpperCase() + ' key saved — paste one and save';
                keyStatus.style.color = '#c62828';
            }
        }
    },

    loadConfig: function() {
        var self = this;
        API.get('/api/transcription/ai-config').then(function(result) {
            if (result.has_config && result.config) {
                self.config = result.config;
                self.populateForm(result.config);
                self.setStatus('Config loaded — ' + result.config.model_name, 'info');
            } else {
                // No config yet — populate defaults
                self.populateDefaults();
                self.setStatus('No config saved yet. Configure and save to get started.', 'warn');
            }
            document.getElementById('aip-test-btn').disabled = false;
            self.loadUsage();
        }).catch(function(err) {
            self.setStatus('Error loading config: ' + err.message, 'error');
        });
    },

    populateForm: function(c) {
        var provider = c.provider || 'groq';
        document.getElementById('aip-provider').value = provider;
        this.updateModelsForProvider(provider);
        var defaultModel = provider === 'openai' ? 'gpt-4.1-mini' : provider === 'gemini' ? 'gemini-2.5-flash' : 'llama-3.3-70b-versatile';
        document.getElementById('aip-model').value = c.model_name || defaultModel;
        document.getElementById('aip-apikey').value = '';
        var hasKey = c[provider + '_key_set'] || false;
        var keyHint = c[provider + '_key_hint'] || null;
        document.getElementById('aip-apikey').placeholder = hasKey ? 'Key saved — paste new to replace' : 'Paste your API key';
        var keyStatus = document.getElementById('aip-key-status');
        if (keyStatus) {
            if (hasKey) {
                keyStatus.textContent = '\u2705 ' + provider.toUpperCase() + ' key saved (' + keyHint + ')';
                keyStatus.style.color = '#2e7d32';
            } else {
                keyStatus.textContent = '\u274c No ' + provider.toUpperCase() + ' key saved';
                keyStatus.style.color = '#c62828';
            }
        }
        document.getElementById('aip-temperature').value = c.temperature || 0.10;
        document.getElementById('aip-temp-val').textContent = parseFloat(c.temperature || 0.10).toFixed(2);
        document.getElementById('aip-max-tokens').value = c.max_tokens || 4096;
        document.getElementById('aip-system-prompt').value = c.system_prompt || this.DEFAULT_SYSTEM_PROMPT;
        document.getElementById('aip-segment-prompt').value = c.segment_prompt || this.DEFAULT_SEGMENT_PROMPT;
        document.getElementById('aip-inc-auction').checked = parseInt(c.include_auction_items) !== 0;
        document.getElementById('aip-inc-players').checked = parseInt(c.include_player_list) !== 0;
        document.getElementById('aip-inc-vocab').checked = parseInt(c.include_card_vocab) !== 0;
        document.getElementById('aip-inc-prev').checked = parseInt(c.include_prev_segment) !== 0;
        this.dirty = false;
        var saveBtn = document.getElementById('aip-save-btn');
        if (saveBtn) { saveBtn.disabled = true; saveBtn.classList.remove('btn-pulse'); }
    },

    populateDefaults: function() {
        document.getElementById('aip-system-prompt').value = this.DEFAULT_SYSTEM_PROMPT;
        document.getElementById('aip-segment-prompt').value = this.DEFAULT_SEGMENT_PROMPT;
        this.markDirty(); // needs initial save
    },

    saveConfig: function(skipReload) {
        var self = this;
        var data = {
            provider: document.getElementById('aip-provider').value,
            model_name: document.getElementById('aip-model').value,
            temperature: parseFloat(document.getElementById('aip-temperature').value),
            max_tokens: parseInt(document.getElementById('aip-max-tokens').value),
            system_prompt: document.getElementById('aip-system-prompt').value,
            segment_prompt: document.getElementById('aip-segment-prompt').value,
            include_auction_items: document.getElementById('aip-inc-auction').checked ? 1 : 0,
            include_player_list: document.getElementById('aip-inc-players').checked ? 1 : 0,
            include_card_vocab: document.getElementById('aip-inc-vocab').checked ? 1 : 0,
            include_prev_segment: document.getElementById('aip-inc-prev').checked ? 1 : 0,
        };

        var apiKey = document.getElementById('aip-apikey').value.trim();
        if (apiKey) data.api_key = apiKey;

        self.setStatus('Saving...', 'info');
        return API.put('/api/transcription/ai-config', data).then(function(result) {
            if (result.success) {
                if (!skipReload) {
                    self.setStatus('Config saved successfully.', 'success');
                    App.toast('AI config saved', 'success');
                    self.loadConfig();
                }
                return true;
            } else {
                self.setStatus('Save failed: ' + (result.error || 'Unknown error'), 'error');
                return false;
            }
        }).catch(function(err) {
            self.setStatus('Save error: ' + err.message, 'error');
            return false;
        });
    },

    testConnection: function() {
        var self = this;
        var apiKey = document.getElementById('aip-apikey').value.trim();
        if (apiKey) {
            // Save key first, then test after save completes
            self.setStatus('Saving key first, then testing...', 'info');
            self.saveConfig(true).then(function(ok) {
                if (ok) {
                    App.toast('API key saved', 'success');
                    self._doTest();
                }
            });
        } else {
            self._doTest();
        }
    },

    _doTest: function() {
        var self = this;
        var model = document.getElementById('aip-model').value;
        console.log('[AiParse] _doTest firing, model=' + model);
        self.setStatus('Testing connection to ' + model + '... (may take 10-30s)', 'info');
        var btn = document.getElementById('aip-test-btn');
        if (btn) btn.disabled = true;

        API.post('/api/transcription/ai-config/test', {}).then(function(result) {
            console.log('[AiParse] test result:', result);
            if (btn) btn.disabled = false;
            if (result.success) {
                self.setStatus('Connection successful! Model: ' + result.model + ' — Response: ' + result.response, 'success');
                App.toast('AI connection OK', 'success');
            } else {
                self.setStatus('Test failed: ' + (result.error || 'Unknown error'), 'error');
            }
        }).catch(function(err) {
            console.error('[AiParse] test error:', err);
            if (btn) btn.disabled = false;
            self.setStatus('Test error: ' + err.message, 'error');
        });
    },

    loadUsage: function() {
        var el = document.getElementById('aip-usage');
        if (!el) return;

        API.get('/api/transcription/ai-config/usage').then(function(result) {
            if (!result.usage) {
                el.innerHTML = '<div class="aip-field-hint">No usage data yet.</div>';
                return;
            }
            var u = result.usage;
            var totalTokens = parseInt(u.total_input_tokens || 0) + parseInt(u.total_output_tokens || 0);
            var h = [];
            h.push('<div class="aip-usage-grid">');
            h.push('<div class="aip-usage-stat"><span class="aip-usage-num">' + parseInt(u.total_requests || 0).toLocaleString() + '</span><span class="aip-usage-label">Requests</span></div>');
            h.push('<div class="aip-usage-stat"><span class="aip-usage-num">' + parseInt(u.total_input_tokens || 0).toLocaleString() + '</span><span class="aip-usage-label">Input Tokens</span></div>');
            h.push('<div class="aip-usage-stat"><span class="aip-usage-num">' + parseInt(u.total_output_tokens || 0).toLocaleString() + '</span><span class="aip-usage-label">Output Tokens</span></div>');
            h.push('<div class="aip-usage-stat"><span class="aip-usage-num">' + totalTokens.toLocaleString() + '</span><span class="aip-usage-label">Total Tokens</span></div>');
            h.push('</div>');

            // Free tier budget bar
            var dailyBudget = 1000000;
            var pct = Math.min(100, (totalTokens / dailyBudget * 100)).toFixed(1);
            h.push('<div class="aip-budget-bar">');
            h.push('<div class="aip-budget-label">Lifetime usage: ' + totalTokens.toLocaleString() + ' tokens</div>');
            h.push('</div>');
            el.innerHTML = h.join('');
        });
    },

    setStatus: function(msg, type) {
        var el = document.getElementById('aip-status');
        if (!el) return;
        var colors = { info: '#e3f2fd', success: '#e8f5e9', warn: '#fff8e1', error: '#ffebee' };
        var textColors = { info: '#1565c0', success: '#2e7d32', warn: '#f57f17', error: '#c62828' };
        el.style.background = colors[type] || colors.info;
        el.style.color = textColors[type] || textColors.info;
        el.textContent = msg;
        el.style.display = msg ? '' : 'none';
    }
};
